// Preparar datos del lead para el email
const lead = $input.first().json;

return {
  email: lead.email,
  name: lead.name || 'Futuro cliente',
  plan: lead.plan || 'pro',
  planName: lead.plan === 'emprendedor' ? 'Emprendedor' : lead.plan === 'business' ? 'Business Escala' : 'PRO',
  planPrice: lead.plan === 'emprendedor' ? 'Gratis para siempre' : lead.plan === 'business' ? '$69 USD/mes' : '$29 USD/mes (50% OFF)',
  discount: lead.plan === 'pro' ? '¡Felicidades! Tienes 50% OFF DE POR VIDA en Plan PRO 🎉' : 'Gracias por tu interés en WASAPEA PRO.',
  source: lead.source || 'wasapea_landing',
  date: new Date().toLocaleDateString('es-CO', { year: 'numeric', month: 'long', day: 'numeric' })
};

